func (s *Store) Fetch(id string) (*Record, error) {
	r, err := s.db.Query("SELECT * FROM records WHERE id = $1", id)
	if err != nil {
		return nil, fmt.Errorf("Store.Fetch: %v", err)
	}
	defer r.Close()
	var rec Record
	if err := r.Scan(&rec); err != nil {
		return nil, fmt.Errorf("Store.Fetch scan: %v", err)
	}
	return &rec, nil
}
